import { defineConfig } from "wxt";

// The manifest is GENERATED by WXT — never hand-author manifest.json.
// All permission/identity facts live here so the privacy invariant
// (host_permissions = docs.google.com only; permissions = storage only)
// is enforced at config time.
export default defineConfig({
  modules: ["@wxt-dev/module-solid", "@wxt-dev/unocss"],
  // Build BOTH browsers as MV3 (Firefox would otherwise default to MV2).
  manifestVersion: 3,
  manifest: ({ browser }) => ({
    name: "DocRewind",
    description: "Local-first Google Docs revision-replay browser extension.",
    permissions: ["storage"],
    host_permissions: ["*://docs.google.com/*"],
    ...(browser === "firefox"
      ? { browser_specific_settings: { gecko: { id: "docrewind@edbpede.github.io" } } }
      : {}),
  }),
  // No DOM in the background — exclude it from UnoCSS processing.
  unocss: { excludeEntrypoints: ["background"] },
});
